module d_ff_async (
    input clk,
    input rst,
    input d,
    output q
);

    reg q_reg;

      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge rst or posedge dbg_halt) begin
        if (rst)
            q_reg <= 1'b0;
        else
            q_reg <= d;
    end

    assign q = q_reg;

endmodule
